import React, { useEffect, useState } from 'react';
import { 
  Users, 
  Activity, 
  Dumbbell, 
  CheckCircle, 
  Calendar,
  Clock,
  Loader2,
  TrendingUp
} from 'lucide-react';
import { supabase } from './lib/supabase';

export function DashboardOverview() {
  const [stats, setStats] = useState({
    totalClients: 0,
    upcomingClasses: [] as any[],
    recentActivity: [] as any[],
    reservasHoy: 0,
    ejerciciosHoy: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchDashboardData() {
      try {
        // Límites del día de hoy en hora local para las consultas
        const todayStart = new Date();
        todayStart.setHours(0, 0, 0, 0);
        const todayEnd = new Date();
        todayEnd.setHours(23, 59, 59, 999);
        const now = new Date();

        // 1. Total Clientes
        const { count: clientCount } = await supabase
          .from('profiles')
          .select('*', { count: 'exact', head: true })
          .eq('role', 'client');

        // 2. Clases de Hoy (Futuras)
        const { data: allTodayClasses } = await supabase
          .from('classes')
          .select('id, title, start_time, trainer')
          .gte('start_time', todayStart.toISOString())
          .lte('start_time', todayEnd.toISOString())
          .order('start_time', { ascending: true });

        const futureClasses = (allTodayClasses || []).filter(cls => new Date(cls.start_time) > now);

        // 3. Nuevas Reservas de Hoy
        const { count: reservasCount } = await supabase
          .from('class_bookings')
          .select('id', { count: 'exact', head: true })
          .gte('booked_at', todayStart.toISOString())
          .lte('booked_at', todayEnd.toISOString());

        // 4. Ejercicios Registrados Hoy (TU TABLA REAL 'workout_logs')
        const { count: workoutCount, error: workoutError } = await supabase
          .from('workout_logs')
          .select('id', { count: 'exact', head: true })
          .gte('logged_at', todayStart.toISOString())
          .lte('logged_at', todayEnd.toISOString());

        if (workoutError) console.error("Error en workout_logs:", workoutError);

        // 5. Actividad Reciente
        const { data: recentProfiles } = await supabase
          .from('profiles')
          .select('id, first_name, last_name, created_at')
          .order('created_at', { ascending: false })
          .limit(3);

        setStats({
          totalClients: clientCount || 0,
          upcomingClasses: futureClasses,
          recentActivity: recentProfiles || [],
          reservasHoy: reservasCount || 0,
          ejerciciosHoy: workoutCount || 0
        });
      } catch (err) {
        console.error("Error cargando Dashboard:", err);
      } finally {
        setLoading(false);
      }
    }

    fetchDashboardData();
  }, []);

  if (loading) {
    return (
      <div className="flex h-96 items-center justify-center">
        <Loader2 className="w-10 h-10 text-[#39FF14] animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      <div>
        <h1 className="text-3xl font-bold text-white tracking-tight">Resumen General</h1>
        <p className="text-gray-400 mt-1">Monitorización de actividad en tiempo real.</p>
      </div>

      {/* Tarjetas de Estadísticas (KPIs) */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        {/* Total Clientes */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-[#39FF14]/30 transition-all group">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Total Clientes</p>
              <h3 className="text-4xl font-black text-white mt-2">{stats.totalClients}</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-[#39FF14]/10 flex items-center justify-center text-[#39FF14] group-hover:scale-110 transition-transform">
              <Users size={20} />
            </div>
          </div>
        </div>

        {/* Clases Pendientes */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-purple-500/30 transition-all group">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Clases Pendientes</p>
              <h3 className="text-4xl font-black text-white mt-2">{stats.upcomingClasses.length}</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-purple-500/10 flex items-center justify-center text-purple-500 group-hover:scale-110 transition-transform">
              <Calendar size={20} />
            </div>
          </div>
        </div>

        {/* Nuevas Reservas */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-blue-500/30 transition-all group">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Nuevas Reservas</p>
              <h3 className="text-4xl font-black text-white mt-2">{stats.reservasHoy}</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-blue-500/10 flex items-center justify-center text-blue-500 group-hover:scale-110 transition-transform">
              <CheckCircle size={20} />
            </div>
          </div>
        </div>

        {/* Ejercicios Completados */}
        <div className="bg-[#121212] border border-[#2a2a2a] p-6 rounded-2xl hover:border-orange-500/30 transition-all group">
          <div className="flex justify-between items-start">
            <div>
              <p className="text-sm font-medium text-gray-400">Ejercicios Hoy</p>
              <h3 className="text-4xl font-black text-white mt-2">{stats.ejerciciosHoy}</h3>
            </div>
            <div className="w-10 h-10 rounded-xl bg-orange-500/10 flex items-center justify-center text-orange-500 group-hover:scale-110 transition-transform">
              <Dumbbell size={20} />
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Próximas Sesiones */}
        <div className="lg:col-span-2 bg-[#121212] border border-[#2a2a2a] rounded-2xl p-6">
          <h2 className="text-lg font-bold text-white flex items-center gap-2 mb-6">
            <TrendingUp className="text-[#39FF14]" size={20} />
            Próximas Sesiones Hoy
          </h2>

          <div className="space-y-4">
            {stats.upcomingClasses.length > 0 ? (
              stats.upcomingClasses.map((cls) => {
                const timeStr = new Date(cls.start_time).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
                return (
                  <div key={cls.id} className="flex items-center justify-between p-4 rounded-xl bg-[#1a1a1a] border border-[#2a2a2a] hover:border-[#39FF14]/30 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className="bg-[#39FF14]/10 text-[#39FF14] px-3 py-1 rounded-lg font-bold text-sm">
                        {timeStr}
                      </div>
                      <h4 className="font-bold text-white">{cls.title}</h4>
                    </div>
                    <span className="text-xs text-gray-500 font-bold uppercase">Coach: {cls.trainer}</span>
                  </div>
                );
              })
            ) : (
              <p className="text-gray-500 text-sm italic py-4">No quedan más clases hoy.</p>
            )}
          </div>
        </div>

        {/* Actividad Reciente */}
        <div className="bg-[#121212] border border-[#2a2a2a] rounded-2xl p-6">
          <h2 className="text-lg font-bold text-white flex items-center gap-2 mb-6">
            <Clock className="text-[#39FF14]" size={20} />
            Últimos Registros
          </h2>
          <div className="space-y-6">
            {stats.recentActivity.map((user) => (
              <div key={user.id} className="flex items-start gap-3">
                <div className="w-2 h-2 mt-2 bg-[#39FF14] rounded-full shadow-[0_0_8px_#39FF14]" />
                <div>
                  <p className="text-sm text-gray-300">
                    <span className="text-white font-bold">{user.first_name} {user.last_name}</span> se ha unido.
                  </p>
                  <p className="text-[10px] text-gray-500 uppercase mt-1">
                    {new Date(user.created_at).toLocaleDateString()}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
